Code.Terraform:
```hcl
# Terraform: Web ACL に少なくとも 1 つのルールがあることを確認する
resource "aws_wafregional_web_acl" "<example_resource_name>" {
  name        = "<example_resource_name>"
  metric_name = "<example_resource_name>"

  default_action {
    type = "ALLOW"
  }

  # 重要: Web ACL が空にならないように、少なくとも 1 つのルールを追加してください
  rules {
    priority = 1
    rule_id  = "<example_resource_id>"
    action {
      type = "BLOCK"
    }
  }
}
```
